export const NUMBERS3_PAGE_SIZE = 25;

/** `numbers3_draws` 行（Supabase / SQLite と同一列） */
export type Numbers3DrawRow = {
  draw_number: number;
  draw_date: string;
  numbers: string;
  tier1_winners: number | null;
  tier1_payout_yen: number | string | null;
  tier2_winners: number | null;
  tier2_payout_yen: number | string | null;
  tier3_winners: number | null;
  tier3_payout_yen: number | string | null;
  tier4_winners: number | null;
  tier4_payout_yen: number | string | null;
};

export const NUMBERS3_DRAW_COLUMNS: {
  key: keyof Numbers3DrawRow;
  label: string;
}[] = [
  { key: "draw_number", label: "回号" },
  { key: "draw_date", label: "抽選日" },
  { key: "numbers", label: "当選番号" },
  { key: "tier1_winners", label: "1等 当選口数" },
  { key: "tier1_payout_yen", label: "1等 払戻金（円）" },
  { key: "tier2_winners", label: "2等 当選口数" },
  { key: "tier2_payout_yen", label: "2等 払戻金（円）" },
  { key: "tier3_winners", label: "3等 当選口数" },
  { key: "tier3_payout_yen", label: "3等 払戻金（円）" },
  { key: "tier4_winners", label: "4等 当選口数" },
  { key: "tier4_payout_yen", label: "4等 払戻金（円）" },
];

/** 詳細ページ用（等級名は楽天表記に合わせる） */
export const NUMBERS3_TIER_DETAIL_LABELS = [
  { tier: 1 as const, label: "ストレート" },
  { tier: 2 as const, label: "ボックス" },
  { tier: 3 as const, label: "セット（ストレート）" },
  { tier: 4 as const, label: "セット（ボックス）" },
];

export function formatYen(value: number | string | null | undefined): string {
  if (value === null || value === undefined) return "—";
  const n = typeof value === "string" ? Number(value) : value;
  if (!Number.isFinite(n)) return "—";
  return n.toLocaleString("ja-JP");
}

export function formatNumbers3Cell(
  key: keyof Numbers3DrawRow,
  row: Numbers3DrawRow,
): string {
  const v = row[key];
  if (v === null || v === undefined) return "—";
  if (key.endsWith("_payout_yen")) return formatYen(v as number | string);
  return String(v);
}

import type { Metadata } from "next";
import Link from "next/link";
import { notFound } from "next/navigation";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { buttonVariants } from "@/components/ui/button-variants";
import { createClient } from "@/lib/supabase/server";
import {
  NUMBERS3_TIER_DETAIL_LABELS,
  type Numbers3DrawRow,
  formatNumbers3Cell,
  formatYen,
} from "@/lib/numbers3";
import { cn } from "@/lib/utils";

export const dynamic = "force-dynamic";

type PageProps = {
  params: Promise<{ draw_number: string }>;
};

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { draw_number } = await params;
  const n = parseInt(draw_number, 10);
  if (!Number.isFinite(n)) return { title: "ナンバーズ3" };
  return {
    title: `第${n}回 ナンバーズ3 当選結果`,
    alternates: { canonical: `/numbers3/result/${n}` },
  };
}

function tierKeys(tier: 1 | 2 | 3 | 4) {
  const w = `tier${tier}_winners` as const;
  const y = `tier${tier}_payout_yen` as const;
  return { w, y };
}

export default async function Numbers3ResultDetailPage({ params }: PageProps) {
  const { draw_number } = await params;
  const n = parseInt(draw_number, 10);
  if (!Number.isFinite(n)) notFound();

  const supabase = await createClient();
  const { data: row, error } = await supabase
    .from("numbers3_draws")
    .select("*")
    .eq("draw_number", n)
    .maybeSingle();
  if (error) throw new Error(error.message);
  if (!row) notFound();

  const r = row as Numbers3DrawRow;

  return (
    <div className="mx-auto w-full max-w-3xl space-y-6 px-4 py-8 sm:px-6 sm:py-10">
      <Link
        href="/numbers3/result"
        className={cn(
          buttonVariants({ variant: "ghost", size: "sm" }),
          "text-muted-foreground -ml-2 hover:text-foreground",
        )}
      >
        ← 一覧へ
      </Link>

      <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10">
        <CardHeader>
          <CardTitle className="text-xl">第 {r.draw_number} 回 ナンバーズ3</CardTitle>
          <CardDescription>抽選日: {r.draw_date}</CardDescription>
        </CardHeader>
        <CardContent className="space-y-8">
          <div>
            <p className="text-muted-foreground text-sm">当選番号</p>
            <p className="font-mono text-5xl font-bold tracking-[0.2em]">
              {String(r.numbers)}
            </p>
          </div>

          <div className="space-y-2">
            <p className="text-foreground text-sm font-medium">当せん口数・払戻金</p>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-[40%]">区分</TableHead>
                  <TableHead className="text-right">当選口数</TableHead>
                  <TableHead className="text-right">払戻金（円）</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {NUMBERS3_TIER_DETAIL_LABELS.map(({ tier, label }) => {
                  const { w, y } = tierKeys(tier);
                  return (
                    <TableRow key={tier}>
                      <TableCell className="text-muted-foreground text-sm">
                        {label}
                      </TableCell>
                      <TableCell className="text-right font-mono text-sm tabular-nums">
                        {formatNumbers3Cell(w, r)}
                      </TableCell>
                      <TableCell className="text-right font-mono text-sm tabular-nums">
                        {formatYen(r[y] as number | string | null)}
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </div>

          <p className="text-muted-foreground text-xs">
            1〜4等の列は、当せんデータのストレート・ボックス・セット（ストレート）・セット（ボックス）に対応しています。
          </p>
        </CardContent>
      </Card>
    </div>
  );
}

